@app.route('/upload')
def upload():
    username = request.args.get('username')
    file_param = request.args.get('file')
    if not username or not file_param:
        return 'Missing parameters', 400
    try:
        filename_part, _ = file_param.split(';', 1)
        if '=' in filename_part:
            filename = filename_part.split('=', 1)[1]
        else:
            filename = filename_part
        if re.search(re.escape(username), filename):
            return 'Username found in filename', 200
        return 'Username not found', 404
    except:
        return 'Invalid file parameter', 400

